<?php
declare(strict_types=1);

function report_contact_where(array &$params): array {
    $where=[visible_contact_sql('c')];
    $contactStatus=(string)($_GET['contact_status']??'active');if($contactStatus==='active')$where[]='c.active=1';elseif($contactStatus==='inactive')$where[]='c.active=0';
    $name=trim((string)($_GET['name']??''));$company=trim((string)($_GET['company']??''));
    if($name!==''){$where[]="CONCAT(c.first_name,' ',c.last_name) LIKE ?";$params[]='%'.$name.'%';}
    if($company!==''){$where[]='c.company LIKE ?';$params[]='%'.$company.'%';}
    if(!empty($_GET['tag'])){$where[]='ct.tag_id=?';$params[]=(int)$_GET['tag'];}
    if(!empty($_GET['tag2'])){if(($_GET['tag_mode']??'and')==='or'){$where[]='ct.tag_id IN (?,?)';$params[]=(int)($_GET['tag']??0);$params[]=(int)$_GET['tag2'];}else{$where[]='EXISTS(SELECT 1 FROM contact_tags rt2 WHERE rt2.contact_id=c.id AND rt2.tag_id=?)';$params[]=(int)$_GET['tag2'];}}
    $older=max(0,min(3650,(int)($_GET['updated_older_days']??0)));if($older)$where[]="c.updated_at<DATE_SUB(NOW(),INTERVAL $older DAY)";
    $within=max(0,min(3650,(int)($_GET['updated_within_days']??0)));if($within)$where[]="c.updated_at>=DATE_SUB(NOW(),INTERVAL $within DAY)";
    $created=max(0,min(3650,(int)($_GET['created_within_days']??0)));if($created)$where[]="c.created_at>=DATE_SUB(NOW(),INTERVAL $created DAY)";
    foreach(['created_from'=>['c.created_at','>='],'created_to'=>['c.created_at','<='],'updated_from'=>['c.updated_at','>='],'updated_to'=>['c.updated_at','<=']] as $key=>[$column,$operator])if(preg_match('/^\d{4}-\d{2}-\d{2}$/',(string)($_GET[$key]??''))){$where[]="$column $operator ?";$params[]=$_GET[$key].($operator==='<='?' 23:59:59':' 00:00:00');}
    $email=$_GET['email_status']??'';if($email==='missing')$where[]="(c.email IS NULL OR c.email='')";elseif($email==='present')$where[]="c.email IS NOT NULL AND c.email<>''";
    $empty=$_GET['empty_field']??'';if(in_array($empty,['company','email','phone'],true))$where[]="(c.$empty IS NULL OR c.$empty='')";
    foreach(custom_field_definitions() as $field){$key='cf_'.$field['id'];$value=trim((string)($_GET[$key]??''));if($value==='')continue;if($field['field_type']==='list'){$where[]='EXISTS(SELECT 1 FROM contact_custom_values rcv WHERE rcv.contact_id=c.id AND rcv.custom_field_id=? AND rcv.field_value=?)';$params[]=(int)$field['id'];$params[]=$value;}else{$where[]='EXISTS(SELECT 1 FROM contact_custom_values rcv WHERE rcv.contact_id=c.id AND rcv.custom_field_id=? AND rcv.field_value LIKE ?)';$params[]=(int)$field['id'];$params[]='%'.$value.'%';}}
    return $where;
}
function report_aggregate(array $rows,string $group): array {
    $counts=[];foreach($rows as $row){$values=[];if($group==='tag')$values=($row['tag_names']??'')?explode(', ',$row['tag_names']):['No tag'];elseif($group==='company')$values=[$row['company']?:'No company'];elseif($group==='score')$values=[$row['score_label']??'No score'];elseif($group==='status')$values=[$row['status_label']??'No status'];elseif($group==='source')$values=[$row['source_label']??'No source'];elseif($group==='event_type')$values=[$row['event_type_label']??'No type'];elseif($group==='event_timing')$values=[$row['timing']??'Unknown'];else $values=['All results'];foreach($values as $value)$counts[$value]=($counts[$value]??0)+1;}arsort($counts);return ['labels'=>array_keys($counts),'values'=>array_values($counts)];
}
if($path==='/api/options'&&($_GET['list']??'')==='event_type'){require_permission('reports.view');header('Content-Type: application/json');echo json_encode(['options'=>array_map(fn($o)=>['code'=>$o['code'],'label'=>$o['label']],list_options('event_type'))]);exit;}
if($path==='/api/report'){
    $requestedDataset=(string)($_GET['dataset']??'contacts');$datasetPermission=['contacts'=>'contacts.view','pipeline'=>'opportunities.view','events'=>'events.view'][$requestedDataset]??'contacts.view';require_permission($datasetPermission);
    require_permission('reports.view');$requested=(string)($_GET['dataset']??'contacts');$dataset=in_array($requested,['contacts','pipeline','events'],true)?$requested:'contacts';$params=[];$where=$dataset==='events'?[]:report_contact_where($params);
    if($dataset==='events'){
        $timing=(string)($_GET['event_timing']??'all');if($timing==='upcoming')$where[]='e.starts_at>=NOW()';elseif($timing==='past')$where[]='e.starts_at<NOW()';$eventType=(string)($_GET['event_type']??'');if(in_array($eventType,option_codes('event_type'),true)){$where[]='e.event_type=?';$params[]=$eventType;}
        $sql="SELECT e.id,e.title,e.event_type,e.starts_at,e.presentation_title,COALESCE(NULLIF(e.presenter_name,''),CONCAT(pc.first_name,' ',pc.last_name)) presenter,e.booking_url,e.conference_url,e.venue_address,e.abstract,COUNT(DISTINCT ea.contact_id) attendees,IF(e.starts_at>=NOW(),'Upcoming','Past') timing FROM events e LEFT JOIN contacts pc ON pc.id=e.presenter_contact_id LEFT JOIN event_attendees ea ON ea.event_id=e.id AND ea.attended=1".($where?' WHERE '.implode(' AND ',$where):'')." GROUP BY e.id ORDER BY e.starts_at DESC LIMIT 2000";$stmt=db()->prepare($sql);$stmt->execute($params);$rows=$stmt->fetchAll();foreach($rows as &$r)$r['event_type_label']=option_label('event_type',$r['event_type']);unset($r);$columns=['title'=>'Event','event_type_label'=>'Type','starts_at'=>'Date','timing'=>'Timing','presentation_title'=>'Presentation','presenter'=>'Presenter','attendees'=>'Attendees','booking_url'=>'Booking URL','conference_url'=>'Conference URL','venue_address'=>'Address','abstract'=>'Abstract'];
    }elseif($dataset==='pipeline'){
        $where[]='o.active=1';
        $score=$_GET['score']??'';$status=$_GET['opportunity_status']??'';$source=$_GET['source']??'';
        if(in_array($score,option_codes('opportunity_score'),true)){$where[]='o.score=?';$params[]=$score;}if(in_array($status,option_codes('opportunity_status'),true)){$where[]='o.status=?';$params[]=$status;}if(in_array($source,option_codes('opportunity_source'),true)){$where[]='o.source_type=?';$params[]=$source;}
        $sql="SELECT o.id,o.title,GROUP_CONCAT(DISTINCT CONCAT(c.first_name,' ',c.last_name) ORDER BY c.last_name SEPARATOR ', ') contacts,GROUP_CONCAT(DISTINCT t.name ORDER BY t.name SEPARATOR ', ') tag_names,MIN(c.company) company,o.score,o.status,o.source_type,o.source_note,e.title source_event,o.value,o.created_at FROM opportunities o JOIN opportunity_contacts oc ON oc.opportunity_id=o.id JOIN contacts c ON c.id=oc.contact_id LEFT JOIN contact_tags ct ON ct.contact_id=c.id LEFT JOIN tags t ON t.id=ct.tag_id LEFT JOIN events e ON e.id=o.source_event_id WHERE ".implode(' AND ',$where).' GROUP BY o.id ORDER BY o.created_at DESC LIMIT 2000';$stmt=db()->prepare($sql);$stmt->execute($params);$rows=$stmt->fetchAll();
        foreach($rows as &$r){$r['score_label']=option_label('opportunity_score',$r['score']);$r['status_label']=option_label('opportunity_status',$r['status']);$r['source_label']=$r['source_type']==='event'?($r['source_event']?:'Event'):option_label('opportunity_source',$r['source_type']);$r['value']=$r['value']!==null?(float)$r['value']:null;}unset($r);
        $columns=['title'=>'Opportunity','contacts'=>'Contacts','company'=>'Company','score_label'=>'Score','status_label'=>'Status','source_label'=>'Source','value'=>'Value','created_at'=>'Created'];
    }else{
        $sql="SELECT c.id,CONCAT(c.first_name,' ',c.last_name) name,c.company,c.email,c.phone,IF(c.active,'Active','Inactive') contact_status,GROUP_CONCAT(DISTINCT t.name ORDER BY t.name SEPARATOR ', ') tag_names,c.created_at,c.updated_at FROM contacts c LEFT JOIN contact_tags ct ON ct.contact_id=c.id LEFT JOIN tags t ON t.id=ct.tag_id WHERE ".implode(' AND ',$where).' GROUP BY c.id ORDER BY c.updated_at DESC LIMIT 2000';$stmt=db()->prepare($sql);$stmt->execute($params);$rows=$stmt->fetchAll();$columns=['name'=>'Contact','company'=>'Company','email'=>'Email','phone'=>'Phone','contact_status'=>'Status','tag_names'=>'Tags','created_at'=>'Created','updated_at'=>'Last updated'];
    }
    if($dataset==='events'){$presenterStmt=db()->prepare("SELECT GROUP_CONCAT(CASE WHEN ep.presenter_type='user' THEN COALESCE(NULLIF(u.display_name,''),u.username) ELSE CONCAT(c.first_name,' ',c.last_name) END ORDER BY 1 SEPARATOR ', ') FROM event_presenters ep LEFT JOIN users u ON ep.presenter_type='user' AND u.id=ep.presenter_id LEFT JOIN contacts c ON ep.presenter_type='contact' AND c.id=ep.presenter_id WHERE ep.event_id=?");foreach($rows as &$row){$presenterStmt->execute([$row['id']]);$row['presenter']=$presenterStmt->fetchColumn()?:$row['presenter'];}unset($row);}
    $aggregate=report_aggregate($rows,(string)($_GET['group_by']??($dataset==='pipeline'?'status':($dataset==='events'?'event_type':'company'))));header('Content-Type: application/json');echo json_encode(['dataset'=>$dataset,'columns'=>$columns,'rows'=>$rows]+$aggregate);exit;
}

if($path!=='/reports')return;
require_permission('reports.view');
if($method==='POST'){require_permission('reports.edit');verify_csrf();$filters=[];foreach(['dataset','filter_name','company','tag','updated_older_days','updated_within_days','created_within_days','email_status','contact_status','opportunity_status','score','source','show_chart'] as $key)$filters[$key]=post($key);foreach(custom_field_definitions() as $field)$filters['cf_'.$field['id']]=post('cf_'.$field['id']);db()->prepare('INSERT INTO saved_reports(user_id,name,chart_type,group_by,filters_json,shared) VALUES(?,?,?,?,?,?)')->execute([user()['id'],trim(post('name')),post('chart_type'),post('group_by'),json_encode($filters),post('shared')?1:0]);flash('success','Report saved.');redirect('/reports');}
$stmt=db()->prepare('SELECT sr.*,u.username FROM saved_reports sr JOIN users u ON u.id=sr.user_id WHERE sr.user_id=? OR sr.shared=1 ORDER BY sr.created_at DESC');$stmt->execute([user()['id']]);$saved=$stmt->fetchAll();
layout('Reports',function()use($saved){?><h1>Report builder</h1><form class="card" id="report-form" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><div class="form-grid"><label>Report name<input name="name" value="CRM report" required></label><label>Dataset<select name="dataset"><option value="contacts">Contacts</option><option value="pipeline">Pipeline opportunities</option></select></label><label>Group chart by<select name="group_by"><option value="company">Company</option><option value="tag">Tag</option><option value="score">Opportunity score</option><option value="status">Opportunity status</option><option value="source">Opportunity source</option></select></label><label>Chart type<select name="chart_type"><option value="bar">Bar</option><option value="pie">Pie</option><option value="doughnut">Doughnut</option></select></label><label>Name contains<input name="filter_name"></label><label>Company contains<input name="company"></label><label>Tag<select name="tag"><option value="">Any</option><?php foreach(all_tags() as $t)if(tag_access((int)$t['id'])!=='hidden'):?><option value="<?=$t['id']?>"><?=e(($t['group_name']?$t['group_name'].' — ':'').$t['name'])?></option><?php endif?></select></label><label>Not updated in more than days<input type="number" min="0" name="updated_older_days" placeholder="30"></label><label>Updated within days<input type="number" min="0" name="updated_within_days"></label><label>Created within days<input type="number" min="0" name="created_within_days"></label><label>Email<select name="email_status"><option value="">Any</option><option value="present">Has email</option><option value="missing">Missing email</option></select></label><label>Pipeline score<select name="score"><option value="">Any</option><?php foreach(list_options('opportunity_score') as $o):?><option value="<?=$o['code']?>"><?=e($o['label'])?></option><?php endforeach?></select></label><label>Pipeline status<select name="opportunity_status"><option value="">Any</option><?php foreach(list_options('opportunity_status') as $o):?><option value="<?=$o['code']?>"><?=e($o['label'])?></option><?php endforeach?></select></label><label>Pipeline source<select name="source"><option value="">Any</option><?php foreach(list_options('opportunity_source') as $o):?><option value="<?=$o['code']?>"><?=e($o['label'])?></option><?php endforeach?></select></label><?php foreach(custom_field_definitions() as $field):?><label>Custom: <?=e($field['name'])?><?php if($field['field_type']==='list'):?><select name="cf_<?=$field['id']?>"><option value="">Any</option><?php foreach($field['options'] as $option):?><option value="<?=e($option['option_value'])?>"><?=e($option['option_value'])?></option><?php endforeach?></select><?php else:?><input name="cf_<?=$field['id']?>" placeholder="Contains…"><?php endif?></label><?php endforeach?></div><div class="actions"><button type="button" id="run">Run report</button><label style="margin:0"><input style="width:auto" type="checkbox" name="show_chart" value="1"> Show chart</label><?php if(can('reports.edit')):?><button class="secondary">Save report</button><label style="margin:0"><input style="width:auto" type="checkbox" name="shared" value="1"> Share</label><?php endif?></div></form><div class="card" id="chart-card" hidden><div class="chart-wrap"><canvas id="chart"></canvas></div></div><div class="card"><div class="actions"><h2 style="margin:0">Results</h2><span class="spacer"></span><span id="result-count" class="muted"></span></div><div style="overflow:auto"><table id="report-table"><thead></thead><tbody></tbody></table></div></div><div class="card"><h2>Saved reports</h2><table><?php foreach($saved as $r):?><tr><td><?=e($r['name'])?></td><td><?=e($r['group_by'])?></td><td><?=e($r['username'])?><?=$r['shared']?' · shared':''?></td><td><button type="button" class="load" data-report='<?=e(json_encode($r))?>'>Load</button></td></tr><?php endforeach?></table></div><script src="https://cdn.jsdelivr.net/npm/chart.js@4.4.7/dist/chart.umd.min.js"></script><script>const f=document.querySelector('#report-form'),head=document.querySelector('#report-table thead'),body=document.querySelector('#report-table tbody'),chartCard=document.querySelector('#chart-card');let chart;async function run(){const p=new URLSearchParams({dataset:f.dataset.value,group_by:f.group_by.value,name:f.filter_name.value,company:f.company.value,tag:f.tag.value,updated_older_days:f.updated_older_days.value,updated_within_days:f.updated_within_days.value,created_within_days:f.created_within_days.value,email_status:f.email_status.value,opportunity_status:f.opportunity_status.value,score:f.score.value,source:f.source.value});f.querySelectorAll("[name^=cf_]").forEach(field=>{if(field.value)p.set(field.name,field.value)});const d=await fetch('/api/report?'+p).then(r=>r.json());head.innerHTML='<tr>'+Object.values(d.columns).map(x=>'<th>'+x+'</th>').join('')+'</tr>';body.replaceChildren(...d.rows.map(row=>{const tr=document.createElement('tr');Object.keys(d.columns).forEach(key=>{const td=document.createElement('td');if((key==='name'&&d.dataset==='contacts')||(key==='title'&&d.dataset==='pipeline')){const a=document.createElement('a');a.href='/'+(d.dataset==='contacts'?'contacts/':'opportunities/')+row.id;a.textContent=row[key]??'';td.append(a)}else td.textContent=row[key]??'';tr.append(td)});return tr}));document.querySelector('#result-count').textContent=d.rows.length+' result'+(d.rows.length===1?'':'s');chartCard.hidden=!f.show_chart.checked;chart?.destroy();if(f.show_chart.checked)chart=new Chart(document.querySelector('#chart'),{type:f.chart_type.value,data:{labels:d.labels,datasets:[{label:'Results',data:d.values,backgroundColor:['#1565c0','#43a047','#f9a825','#8e24aa','#e53935','#00838f']}]},options:{responsive:true,maintainAspectRatio:false}})}document.querySelector('#run').onclick=run;f.show_chart.onchange=run;document.querySelectorAll('.load').forEach(b=>b.onclick=()=>{const r=JSON.parse(b.dataset.report),x=JSON.parse(r.filters_json);f.name.value=r.name;f.group_by.value=r.group_by;f.chart_type.value=r.chart_type;for(const [k,v] of Object.entries(x)){const field=f.elements[k];if(field)field.type==='checkbox'?field.checked=!!v:field.value=v||''}run()});run()</script><?php });exit;

